insert into public.regulations (slug,title,category,summary,doc_number,authority,issued_date,status,status_note,source_url,source_filename,relevance,sort_order,published,featured) values
('cmr-2017-amendments-consolidated-2024','Coal Mines Regulations, 2017 — Consolidated Amendments (2018–2024)','cmr_2017','A single consolidated gazette compilation, published by DGMS on 3 July 2024, bringing together the amendments made to the Coal Mines Regulations, 2017 between 2018 and 2024. DGMS issues these changes as one combined document rather than separate year-by-year notifications, so this file is the reference point for the current amended text of CMR 2017.',null,'DGMS','2024-07-03','in_force','Amends CMR 2017; CMR 2017 remains operative.','https://www.dgms.gov.in/writereaddata/UploadFile/GAZETTE_NOTIFICATIONS_03072024.pdf','CMR2017_Amendments_Consolidated_GazetteNotifications_03072024.pdf',1,11,true,true),
('cmr-2017-amendment-assistant-manager-2025','CMR 2017 Amendment — Scale of Appointment of Assistant Manager (Reg. 30)','cmr_2017','Amendment to the Coal Mines Regulations, 2017 notified as G.S.R. 640(E) on 9 October 2025, revising the scale for appointment of Assistant Managers in coal mines (the Regulation 30 cluster). It updates the manpower-to-management ratios coal mine operators must maintain for statutory supervisory staffing.','G.S.R. 640(E)','DGMS','2025-10-09','in_force','Amends CMR 2017 (Reg. 30); CMR 2017 remains operative.','https://www.dgms.gov.in/writereaddata/UploadFile/26620dd_09102025.pdf','CMR2017_Amendment_AssistantManager_GSR640E_09102025.pdf',1,12,true,false),
('cmr-2017-amendment-gas-testing-certificate-2025','Coal Mines Regulations 2017 Amendment - Gas Testing Competency Certificate (2025)','cmr_2017','A DGMS notification (G.S.R. 491(E), dated 22 July 2025) issued under Regulations 12(1) and 12(4) of the Coal Mines Regulations, 2017, laying down the applicability and eligibility criteria for grant of the Gas Testing Competency Certificate to persons authorised to test for inflammable gas in underground coal mines.','Notification 08/2025','DGMS','2025','in_force','Amends CMR 2017; CMR 2017 remains operative. (Related 2021 competency bye-laws withdrawn 23 Mar 2026.)','https://www.dgms.gov.in/writereaddata/UploadFile/GT_CMR_2017_082025.pdf','CMR2017_Amendment_GasTestingCertificate_2025.pdf',2,13,true,false),
('draft-oshwc-coal-mines-regulations-2026','Draft OSH&WC (Coal Mines) Regulations, 2026','draft','The Draft Occupational Safety, Health and Working Conditions (Coal Mines) Regulations, 2026, published as G.S.R. 67(E) on 28 January 2026 for a 45-day public consultation. Framed under Section 136 of the OSH&WC Code, 2020 (not the Mines Act, 1952), these draft regulations are intended eventually to replace the Coal Mines Regulations, 2017. IMPORTANT: this is a DRAFT and is NOT in force — CMR 2017 remains the operative law.','G.S.R. 67(E)','DGMS','2026-01-28','draft','Draft — 45-day public consultation; NOT in force. CMR 2017 remains operative.','https://www.dgms.gov.in/writereaddata/UploadFile/CMR_GN_31012026.pdf','CMR_GN_31012026.pdf',1,20,true,true),
('mines-act-1952','The Mines Act, 1952','mines_act','The principal Act of Parliament (No. 35 of 1952) that consolidates the law regulating labour and safety in mines across India, defining key terms and the powers of the Chief Inspector of Mines.','Act 35 of 1952','Ministry of Labour & Employment','1952','superseded','Subsumed by the OSH&WC Code, 2020 (in force 21 Nov 2025); subordinate rules continue under savings.','https://www.dgms.gov.in/writereaddata/UploadFile/Mines_Act_1952.pdf','Mines_Act_1952.pdf',1,30,true,true),
('mines-rules-1955','The Mines Rules, 1955','mines_act','Rules made under Section 58 of the Mines Act, 1952 (SRO 1421 dated 2 July 1955) governing the general administration of mines, including canteens, notices, forms and duties of managers.',null,'Ministry of Labour & Employment','1955','in_force','Continues in force under the OSH&WC Code transition (savings), pending replacement.','https://www.dgms.gov.in/writereaddata/UploadFile/Mines_Rules_1955.pdf','Mines_Rules_1955.pdf',1,31,true,true),
('mines-rescue-rules-1985','The Mines Rescue Rules, 1985','mines_act','Rules (G.S.R. 325(E) dated 29 March 1985) made under the Mines Act, 1952 prescribing rescue-station and rescue-brigade requirements for below-ground mines.',null,'DGMS','1985','in_force','Continues in force under the OSH&WC Code transition (savings), pending replacement.','https://www.dgms.gov.in/writereaddata/UploadFile/Mines_Rescue_Rules,_1985.pdf','Mines_Rescue_Rules,_1985.pdf',2,32,true,true),
('mines-vocational-training-rules-1966','The Mines Vocational Training Rules, 1966','mines_act','Rules under the Mines Act, 1952 requiring and prescribing vocational training for persons employed in mines before they are put to work.',null,'DGMS','1966','in_force','Continues in force under the OSH&WC Code transition (savings), pending replacement.','https://www.dgms.gov.in/writereaddata/UploadFile/Mines_Vocational_Training_Rules_1966.pdf','Mines_Vocational_Training_Rules_1966.pdf',2,33,true,true),
('coal-mines-regulations-1957','The Coal Mines Regulations, 1957','mines_act','Regulations (S.R.O. 3419 dated 24 October 1957) made under Section 57 of the Mines Act, 1952, superseding the Indian Coal Mines Regulations, 1926, and governing safety in every coal mine in India (later superseded by CMR 2017).',null,'DGMS','1957','superseded','Superseded by the Coal Mines Regulations, 2017. Retained for reference.','https://www.dgms.gov.in/','Coal_Mines_Regulations_1957.pdf',3,34,true,false),
('metalliferous-mines-regulations-1961','Metalliferous Mines Regulations, 1961 — Second Class Manager''s Certificate candidate list','mines_act','This file is actually a list of candidates granted the Second Class Manager''s Certificate of Competency (Restricted) on examination basis under the MMR 1961, not the Regulations themselves.',null,'DGMS','1961','in_force','Current safety code for metalliferous (non-coal) mines; analogue reference for coal.','https://www.dgms.gov.in/writereaddata/UploadFile/MMR_1961.pdf','MMR_1961.pdf',2,35,false,false),
('code-on-wages-2019','The Code on Wages, 2019','labour_code','The Code on Wages, 2019 consolidates and replaces four earlier laws — the Payment of Wages Act, the Minimum Wages Act, the Payment of Bonus Act and the Equal Remuneration Act. It establishes a universal floor wage, statutory minimum wages, timely payment of wages and bonus, and equal pay, and applies to all establishments including coal mines. The four Labour Codes were brought into force on 21 November 2025.',null,'Ministry of Labour & Employment','2019','in_force','In force from 21 Nov 2025.','https://labour.gov.in/','The Code on Wages, 2019.pdf',2,40,true,true),
('industrial-relations-code-2020','The Industrial Relations Code, 2020','labour_code','The Industrial Relations Code, 2020 consolidates the Trade Unions Act, the Industrial Employment (Standing Orders) Act and the Industrial Disputes Act. It governs trade union recognition, standing orders, retrenchment and layoff, grievance redressal, strikes and lock-outs, and dispute resolution machinery. It applies to industrial establishments including mines and was brought into force on 21 November 2025.',null,'Ministry of Labour & Employment','2020','in_force','In force from 21 Nov 2025.','https://labour.gov.in/','The Industrial Relations Code, 2020.pdf',2,41,true,true),
('oshwc-code-2020','The Occupational Safety, Health and Working Conditions Code, 2020','labour_code','The OSH&WC Code, 2020 consolidates thirteen labour laws on occupational safety, health and working conditions — including the Mines Act, 1952 and the Factories Act — into a single code. It covers working conditions, welfare facilities, hours of work, and safety obligations of employers, and provides the statutory basis (Section 136) under which the Draft OSH&WC (Coal Mines) Regulations, 2026 are being framed. It came into force on 21 November 2025.',null,'Ministry of Labour & Employment','2020','in_force','In force from 21 Nov 2025; subsumes the Mines Act, 1952 (subordinate rules continue under savings).','https://labour.gov.in/','The Occupational Safety, Health and Working Conditions Code, 2020.pdf',2,42,true,true),
('code-on-social-security-2020','The Code on Social Security, 2020','labour_code','The Code on Social Security, 2020 consolidates nine social-security laws covering provident fund, employees'' state insurance, gratuity, maternity benefit, and the extension of social security to gig, platform and unorganised workers. It applies to establishments including coal mines and was brought into force on 21 November 2025.',null,'Ministry of Labour & Employment','2020','in_force','In force from 21 Nov 2025.','https://labour.gov.in/','The Code on Social Security, 2020.pdf',2,43,true,true),
('code-on-wages-central-rules-2026','Code on Wages (Central) Rules, 2026','labour_code','The Code on Wages (Central) Rules, 2026 are the final central rules operationalising the Code on Wages, 2019 for establishments under central-sphere jurisdiction. Published on 8 May 2026, they prescribe the manner of fixing minimum wages, floor wage, deductions, payment mechanisms and record-keeping.',null,'Ministry of Labour & Employment','2026','in_force','Final central rules published 8 May 2026.','https://labour.gov.in/','Code on Wages (Central) Rules, 2026.pdf',2,44,true,false),
('industrial-relations-code-central-rules-2026','Industrial Relations Code (Central) Rules, 2026','labour_code','The Industrial Relations Code (Central) Rules, 2026 are the final central rules under the Industrial Relations Code, 2020, published on 8 May 2026. They detail procedures for trade union registration, standing orders, works committees, grievance redressal, and notices of change, layoff and retrenchment.',null,'Ministry of Labour & Employment','2026','in_force','Final central rules published 8 May 2026.','https://labour.gov.in/','Industrial Relations Code (Central) Rules, 2026.pdf',2,45,true,false),
('oshwc-code-central-rules-2026','Occupational Safety, Health and Working Conditions Code (Central) Rules, 2026','labour_code','The OSH&WC Code (Central) Rules, 2026 are the final central rules under the OSH&WC Code, 2020, published on 8 May 2026. They prescribe working-condition standards, welfare facilities, safety committees, health and working-hours requirements and duties of employers for central-sphere establishments.',null,'Ministry of Labour & Employment','2026','in_force','Final central rules published 8 May 2026.','https://labour.gov.in/','Occupational Safety, Health and Working Conditions Code (Central) Rules, 2026.pdf',2,46,true,false),
('social-security-code-central-rules-2026','Social Security Code (Central) Rules, 2026','labour_code','The Social Security Code (Central) Rules, 2026 are the final central rules under the Code on Social Security, 2020, published on 8 May 2026. They set out the administration of provident fund, ESI, gratuity, maternity benefit and social-security coverage for gig, platform and unorganised workers.',null,'Ministry of Labour & Employment','2026','in_force','Final central rules published 8 May 2026.','https://labour.gov.in/','Social Security Code (Central) Rules, 2026.pdf',2,47,true,false),
('model-standing-orders-2026','Model Standing Orders, 2026','labour_code','The Model Standing Orders, 2026 issued under the Industrial Relations Code, 2020 provide the default terms of employment — classification of workers, working hours, attendance, leave, conduct and discipline, and termination — applicable to industrial establishments, including mines, until certified standing orders are in place.',null,'Ministry of Labour & Employment','2026','in_force',null,'https://labour.gov.in/','Model Standing Orders 2026.pdf',2,48,true,false),
('mmdr-act-1957','Mines and Minerals (Development and Regulation) Act, 1957','mmdr','The MMDR Act, 1957 is the central law regulating the development and regulation of mines and minerals other than petroleum and natural gas. It governs the grant of mineral concessions (prospecting licences, mining leases and mineral auctions), royalty and the District Mineral Foundation, and empowers rules on mineral conservation and development. This consolidated version incorporates amendments through 2023.','Act 67 of 1957','Ministry of Mines','1957','in_force',null,'https://www.indiacode.nic.in/bitstream/123456789/1421/3/A1957-67.pdf','MMDR_Act_1957_consolidated.pdf',2,50,true,true),
('mineral-conservation-development-rules-2017','Mineral Conservation and Development Rules, 2017','mmdr','Rules notified under the Mines and Minerals (Development and Regulation) Act, 1957 prescribing scientific and systematic mining, mining-plan and mine-closure requirements, mineral conservation measures and reporting to the Indian Bureau of Mines, applying to all minerals except petroleum, natural gas, coal, lignite, stowing sand and minor minerals.','G.S.R. 144(E)','Ministry of Mines','2017-02-27','in_force',null,'https://ibm.gov.in/writereaddata/files/04192017182323MCDR_2017.pdf','MCDR_2017_principal.pdf',2,51,true,false),
('mineral-concession-rules-2016','Minerals (Other than Atomic and Hydrocarbon Energy Minerals) Concession Rules, 2016','mmdr','The Mineral Concession Rules, 2016 (MCR 2016), made under the MMDR Act, 1957, govern the grant, renewal, transfer and management of mineral concessions such as mining leases and prospecting licence-cum-mining leases. This copy is amended up to January 2026.',null,'Ministry of Mines','2016','in_force',null,'https://ibm.gov.in/writereaddata/files/17714807906996a6d62cf4fMCR_2016_amended_upto_January_2026.pdf','MCR_2016_amended_Jan2026.pdf',3,52,true,false),
('mineral-auction-rules-2015','Mineral (Auction) Rules, 2015','mmdr','The Mineral (Auction) Rules, 2015, made under the MMDR Act, 1957, set out the procedure for auctioning mineral blocks — the method of competitive bidding, eligibility, technical and financial conditions, and grant of mining leases through auction. This version is amended up to 29 January 2026.',null,'Ministry of Mines','2015','in_force',null,'https://ibm.gov.in/writereaddata/files/177132228869943bb04a7b6Mineral_Auction_Rules_2015_Amended_upto_29.01.2026.pdf','Mineral_Auction_Rules_2015_amended_29012026.pdf',3,53,true,false),
('eia-notification-2006','Environmental Impact Assessment (EIA) Notification, 2006','env_forest','The EIA Notification, 2006 (S.O. 1533(E)), issued under the Environment (Protection) Act, 1986, makes prior environmental clearance mandatory for listed projects including coal mining. It sets out the screening, scoping, public consultation and appraisal process, categorises projects (A and B), and defines the role of the EAC/SEIAA. It is the core environmental-clearance regime that coal mine expansions and new projects must comply with.','S.O. 1533(E)','Ministry of Environment, Forest and Climate Change','2006-09-14','in_force',null,'https://environmentclearance.nic.in/writereaddata/EIA_Notifications/1_SO1533E_14092006.pdf','EIA_Notification_2006_PRINCIPAL_SO1533E.pdf',2,60,true,true),
('van-sanrakshan-evam-samvardhan-rules-2023','Van (Sanrakshan Evam Samvardhan) Rules, 2023','env_forest','The Van (Sanrakshan Evam Samvardhan) Rules, 2023, in force from 1 December 2023, are made under the Van (Sanrakshan Evam Samvardhan) Adhiniyam (Forest (Conservation) Act, 1980, as amended). They prescribe the procedure for prior approval to divert forest land for non-forest use such as mining, including proposal processing, compensatory afforestation and conditions of approval. These Rules replaced the Forest (Conservation) Rules, 2022.',null,'Ministry of Environment, Forest and Climate Change','2023-12-01','in_force','In force from 1 Dec 2023.','https://forestsclearance.nic.in/writereaddata/Rules/VanSanrakshanEvamSamvardhanRules2023.pdf','Van_Sanrakshan_Samvardhan_Rules_2023.pdf',2,61,true,true),
('forest-conservation-rules-2022','Forest (Conservation) Rules, 2022 (superseded)','env_forest','The Forest (Conservation) Rules, 2022 (G.S.R. 480(E)) prescribed the earlier procedure for approval of forest-land diversion for non-forest uses including mining. They have been superseded by the Van (Sanrakshan Evam Samvardhan) Rules, 2023, which took effect on 1 December 2023, and are retained for reference only.','G.S.R. 480(E)','Ministry of Environment, Forest and Climate Change','2022-06-28','superseded','Superseded by the Van (Sanrakshan Evam Samvardhan) Rules, 2023 (in force 1 Dec 2023).','https://forestsclearance.nic.in/writereaddata/public_display/schemes/465954314$15%2009%202022.pdf','Forest_Conservation_Rules_2022.pdf',3,62,true,false),
('van-adhiniyam-eia-forest-clearance-note','EIA Notification 2006 — Consolidated Amendments Index','env_forest','A consolidated index of the amendments to the EIA Notification, 2006, listing the S.O. numbers and dates of the numerous amendments made since 2006. It is a navigational reference to track how the environmental-clearance regime has evolved alongside the principal notification.',null,'Ministry of Environment, Forest and Climate Change','2006-09-14','in_force',null,'https://environmentclearance.nic.in/writereaddata/EIA%20Notifications.pdf','EIA_Notification_2006_consolidated.pdf',2,63,true,false),
('moc-mining-plan-mine-closure-guidelines-2025','Ministry of Coal Mining Plan and Mine Closure Plan Guidelines, 2025 (MPG-2025)','moc','Guidelines issued by the Ministry of Coal on 31 January 2025 consolidating the framework for preparing mining plans and progressive and final mine closure plans for coal and lignite mines, covering approving agencies, plan contents and closure-cost provisioning.','F.No. CPAM-34011/28/2019-CPAM','Ministry of Coal','2025-01-31','in_force',null,'https://coalcontroller.gov.in/files/guidelines-acts-documents/final-mp-guidelines-2025.pdf','MPG_2025_MiningPlan_MineClosure_Guidelines_31012025.pdf',1,70,true,false),
('moc-mpg-2025-corrigendum','Corrigendum to MPG-2025 (26 May 2025)','moc','A corrigendum/revision issued by the Ministry of Coal on 26 May 2025 to the Mining Plan and Mine Closure Plan Guidelines, 2025 (MPG-2025), correcting and clarifying provisions of the principal guidelines.',null,'Ministry of Coal','2025-05-26','in_force',null,'https://coal.gov.in/sites/default/files/2025-05/26-05-2025rule.pdf','MPG_2025_Corrigendum_26052025.pdf',2,71,true,false),
('moc-mining-plan-guidelines-2019','Mining Plan Guidelines, 2019 (closure-cost basis; superseded)','moc','The Ministry of Coal Mining Plan Guidelines dated 16 December 2019 established the mine-closure-cost rate basis (per-hectare provisioning, with a base date of 1 April 2019) underpinning escrow arrangements for coal mines. Though superseded by MPG-2025, they remain the key reference for the closure-cost rate basis.',null,'Ministry of Coal','2019-12-16','superseded','Superseded by MPG-2025 (31 Jan 2025); retained for the closure-cost rate basis.','https://coal.nic.in/sites/default/files/2020-01/Guidelines-for-Mining-plan-Coal_16122019.pdf','MP_Guidelines_2019_16122019_closure-cost-basis.pdf',2,72,true,false),
('cea-safety-electric-supply-regulations-2023','Central Electricity Authority (Measures relating to Safety and Electric Supply) Regulations, 2023','cea','CEA notification dated 8 June 2023 (Gazette Part III Sec.4) issued under the Electricity Act, 2003, superseding the 2010 regulations and prescribing safety measures for construction, operation and maintenance of electrical plants and lines.',null,'CEA','2023','in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/CEA_Safety_and_Electric_Supply_Regulations_2023.pdf','CEA_Safety_and_Electric_Supply_Regulations_2023.pdf',2,80,true,false),
('cea-measures-relating-to-safety-regulations-2010','Central Electricity Authority (Measures relating to Safety and Electric Supply) Regulations, 2010','cea','CEA regulations of 2010 made under the Electricity Act, 2003 prescribing safety measures for electric supply and installations (superseded by the 2023 regulations).',null,'CEA','2010','superseded','Superseded by the CEA Safety Regulations, 2023.','https://www.dgms.gov.in/writereaddata/UploadFile/Central_Electricity_Authority_Regulation,_2010637600519423685101.pdf','Central_Electricity_Authority_Regulation,_2010637600519423685101.pdf',2,81,true,false),
('dgms-tech-st-circular-02-2025-ventilation','DGMS (Tech)(S&T) Circular 02 of 2025 — Minimum air quantity at Continuous Miner and Longwall panels','dgms_circular','DGMS circular dated 17 April 2025 issuing guidelines on the minimum air quantity required at Continuous Miner and Longwall mass-production panels under Regulation 153 of the Coal Mines Regulations, 2017.','Tech (S&T) 02/2025','DGMS','2025-04-17','in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/DGMSTechCir2of2025_Ventilation_17042025.pdf','DGMSTechCir2of2025_Ventilation_17042025.pdf',2,90,true,true),
('dgms-tech-circular-01-2025-explosives','DGMS (Tech) Circular 01 of 2025 — Quality and Condition of Explosive Materials','dgms_circular','DGMS Technical Circular 01 of 2025, dated 17 April 2025, addresses the quality and condition of explosive materials used in mines, prescribing precautions for their storage, handling and use to prevent misfires and premature blasts.','Tech 01/2025','DGMS','2025-04-17','in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/DGMSTechCir01of2025_17042025.pdf','DGMSTechCir01of2025_17042025.pdf',2,91,true,true),
('dgms-tech-circular-05-2025-underground-mines-safety','DGMS (Tech) Circular 05 of 2025 — Underground Coal and Metalliferous Mines Safety','dgms_circular','DGMS Technical Circular 05 of 2025, dated 8 October 2025, issues directions on safety in underground coal and metalliferous mines, reinforcing precautions for safe underground working.','Tech 05/2025','DGMS','2025-10-08','in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/TechCircular5_08102025.pdf','TechCircular5_08102025.pdf',2,92,true,true),
('dgms-tech-circular-06-2025-fall-from-height','DGMS (Tech) Circular 06 of 2025 — Prevention of Fall of Person from Height or into Depth','dgms_circular','DGMS Technical Circular 06 of 2025, dated 24 November 2025, prescribes precautions to prevent fall-of-person accidents from height or into depth in mines, including edge protection, fall-arrest arrangements and safe work practices.','Tech 06/2025','DGMS','2025-11-24','in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/circular6New_24112025.pdf','circular6New_24112025.pdf',2,93,true,true),
('dgms-tech-circular-02-2024-inundation','DGMS (Tech) Circular 02 of 2024 — Precautions Against Danger of Inundation','dgms_circular','DGMS Technical Circular 02 of 2024, dated 22 May 2024, prescribes precautions against the danger of inundation (water inrush) in mines, including surveys of old and adjacent workings, barriers and advance boreholes. It supports the inundation-related provisions of the Coal Mines Regulations, 2017.','Tech 02/2024','DGMS','2024-05-22','in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/InundationCircular_23052024.pdf','InundationCircular_23052024.pdf',2,94,true,false),
('dgms-tech-circular-03-2020-scientific-study-reg-106','DGMS (Tech) Circular 03 of 2020 — Guideline for Scientific Study under Regulation 106','dgms_circular','DGMS Technical Circular 03 of 2020, dated 16 January 2020, lays down the guideline for conducting the scientific study of strata behaviour and support required under Regulation 106 of the Coal Mines Regulations, before adopting depillaring or mechanised extraction.','Tech 03/2020','DGMS','2020-01-16','in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/DGMST2020.pdf','DGMST2020.pdf',2,95,true,false),
('dgms-tech-circular-10-2020-lightning-protection','DGMS (Tech) Circular 10 of 2020 — Lightning Protection in Mines','dgms_circular','DGMS Technical Circular 10 of 2020 prescribes measures for lightning protection in mines, particularly to prevent lightning-induced initiation of explosives and hazards to surface installations.','Tech 10/2020','DGMS','2020','in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/dgmscirrr.pdf','dgmscirrr.pdf',2,96,true,false),
('dgms-tech-circular-13-2020-medical-examination','DGMS (Tech) Circular 13 of 2020 — Medical Examination (Regulation 31)','dgms_circular','DGMS Technical Circular 13 of 2020 addresses the initial and periodical medical examination of persons employed in mines and the certificate of fitness, clarifying obligations under the medical-examination regulations. It is a common compliance reference for occupational-health requirements.','Tech 13/2020','DGMS','2020','in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/medical_cert_fitness.pdf','medical_cert_fitness.pdf',2,97,true,false),
('dgms-tech-circular-14-2020-site-mixed-emulsion','DGMS (Tech) Circular 14 of 2020 — Precautions Against Premature Blast of Site Mixed Emulsion','dgms_circular','DGMS Technical Circular 14 of 2020 prescribes precautions against premature blasting when using Site Mixed Emulsion (SME) explosives in opencast mines, covering charging, stemming and safe handling to prevent accidents.','Tech 14/2020','DGMS','2020','in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/DGMS_cir_14.pdf','DGMS_cir_14.pdf',2,98,true,false),
('dgms-approval-01-2020-man-riding-systems','DGMS Approval Circular 01 of 2020 — Standards for Man Riding Systems in Mines','dgms_circular','DGMS Approval Circular 01 of 2020 adopts standards for Man Riding Systems used to transport persons in mines (including underground man-riding installations), specifying design, safety and approval requirements.','Approval 01/2020','DGMS','2020','in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/DGMScir2.pdf','DGMScir2.pdf',2,99,true,false),
('dgms-tech-circular-01-2018-diesel-equipment-standards','DGMS (Tech) Circular 01 of 2018 — Diesel Equipment Standards','dgms_circular','DGMS Technical Circular 01 of 2018 lays down standards for diesel-operated equipment used in coal and metalliferous mines, covering permissibility, exhaust conditioning and safe use of diesel machinery underground and on surface.','Tech 01/2018','DGMS','2018','in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/Cir_2018_01_SnT_Tech636707023791212360.pdf','Cir_2018_01_SnT_Tech636707023791212360.pdf',2,100,true,false),
('dgms-tech-circular-01-2021-first-aid-training','DGMS (Tech) Circular 01 of 2021 — First-Aid Training and Certification Standards','dgms_circular','DGMS Technical Circular 01 of 2021, dated 6 August 2021, prescribes standards for the conduct of first-aid training and the issue of first-aid certificates for persons employed in mines, supporting statutory first-aid and emergency-preparedness requirements.','Tech 01/2021','DGMS','2021-08-06','in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/DGMS_tech.pdf','DGMS_tech.pdf',2,101,true,false),
('dgms-legis-circular-2019-women-employment','DGMS (Legis) Circular 2019 — Equal Employment Opportunity for Women in Mines','dgms_circular','The DGMS Legislative Circular of 2019 (revised) provides for equal employment opportunity for women in mines, including deployment of women in below-ground and opencast workings beyond earlier restricted hours, subject to conditions and safeguards.',null,'DGMS','2019','in_force',null,'https://www.dgms.gov.in/','Merged_Circular_1.pdf',2,102,true,false),
('explosives-rules-2008','The Explosives Rules, 2008','dgms_circular','Rules (G.S.R. 907(E) dated 29 December 2008) made under Sections 5 and 7 of the Explosives Act, 1884, superseding the Explosives Rules, 1983, and governing manufacture, storage, transport and use of explosives.',null,'DGMS','2008','in_force','Current explosives rules under the Explosives Act, 1884 (PESO).','https://www.dgms.gov.in/','ExplosivesRules,_2008.pdf',2,103,true,false),
('dgms-tech-circular-26-of-2026-30-06-2026','DGMS (Tech) Circular 26 of 2026 (30.06.2026)','dgms_circular','Revises the DGMS-approved list of laboratories permitted to test the standard properties of chemical additives used for dust suppression in coal mines, broadening it beyond the four originally named institutions to include other government laboratories and test houses so more manufacturers can participate.',null,'DGMS','2026','in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/cir_26_30062026.pdf','cir_26_30062026.pdf',1,210,true,false),
