('09-safetyalert-20082025','DGMS Safety Alert 09/2025 — Fatal fall from height at ONGC WD-51 Workover Oil Well Mine, Gujarat','dgms_circular','Reports a fatal 20 m fall of a contractual topman climbing a workover-rig ladder at ONGC''s WD-51 mine and recommends full-body harnesses, secured ladders, and guarded monkey boards to prevent recurrence.',null,'DGMS',null,'in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/09_SAFETYALERT_20082025.pdf','09_SAFETYALERT_20082025.pdf',2,320,true,false),
('10-safetyalert-20082025','DGMS Safety Alert 10/2025 — Fatal blasting-projectile accident at Gare Palma IV/2&3 Opencast Coal Mine, Chhattisgarh','dgms_circular','Reports a deep-hole blasting projectile that penetrated a truck-mounted blasting shelter 165 m away at Jindal Power''s Gare Palma opencast mine, killing two and injuring one, as a safety warning to the industry.',null,'DGMS',null,'in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/10_SafetyAlert_20082025.pdf','10_SafetyAlert_20082025.pdf',2,320,true,false),
('11-safetyalert-20082025','DGMS Safety Alert 11/2025 — Fatal accident from fall of person handling water hose of twin bolter machine, Churcha Mine (SECL)','dgms_circular','Reports a fatal accident at Churcha Mine (SECL), Korea district, Chhattisgarh, where a contractor worker handling the water hose of a stuck twin bolter machine during recovery was struck by its rear side, and recommends a detailed SOP for recovery of stuck machinery, demarcation of danger zones and use of hydraulic equipment retrievers.',null,'DGMS',null,'in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/11_SafetyAlert_20082025.pdf','11_SafetyAlert_20082025.pdf',2,320,true,false),
('12-safetyalert-20082025','DGMS Safety Alert 12/2025 — Fatal accident from overturning of employee bus at Dulanga Coal Mine (NTPC)','dgms_circular','Reports a fatal accident at Dulanga Coal Mining Project (NTPC), Sundargarh, Odisha, where a bus carrying mine employees overturned killing a person standing at an open door, and recommends automatic door-locking, driver rest periods, road maintenance and pre-trip fitness checks for LMV transport.',null,'DGMS',null,'in_force',null,'https://www.dgms.gov.in/writereaddata/UploadFile/12_Safetyalert_20082025.pdf','12_Safetyalert_20082025.pdf',2,320,true,false),
